const usernameField=document.getElementById("username-field"),searchForm=document.getElementById("search-form"),results=document.getElementById("results"),encodedField=document.getElementById("encoded-id"),errorElem=document.getElementById("error"),idField=document.getElementById("user-id"),usernameElem=document.getElementById("username"),copyId=document.getElementById("copy-id"),copyEncoded=document.getElementById("copy-encoded"),submitBtn=document.getElementById("submit-btn");searchForm.addEventListener("submit",(async e=>{e.preventDefault(),submitBtn.innerText="Searching...",submitBtn.disabled=!0;const t=await fetch(`https://psn.flipscreen.games/search.php?username=${usernameField.value}`),n=await t.json();200==t.status?(usernameElem.innerText=n.online_id,idField.value=n.user_id,encodedField.value=n.encoded_id,errorElem.innerText="",searchForm.style.display="none",results.style.display="block"):(errorElem.innerText=n.error,submitBtn.innerText="Submit",submitBtn.disabled=!1)})),copyEncoded.addEventListener("click",(()=>{navigator.clipboard.writeText(encodedField.value),copyEncoded.innerText="Copied!",window.setTimeout((()=>{copyEncoded.innerText="Copy"}),1500)})),copyId.addEventListener("click",(()=>{navigator.clipboard.writeText(idField.value),copyId.innerText="Copied!",window.setTimeout((()=>{copyId.innerText="Copy"}),1500)}));